// Example: disclose AI involvement and provide opt-out
interface AIDecisionResponse {
  recommendation: string;
  confidence: number;
  isAIGenerated: boolean;  // always true for AI outputs
  explanationSummary: string;  // what factors drove this output
  appealUrl?: string;  // for consequential decisions
}

function renderDecisionCard(decision: AIDecisionResponse) {
  return {
    heading: decision.recommendation,
    badge: decision.isAIGenerated ? "AI-assisted recommendation" : "Human decision",
    explanation: decision.explanationSummary,
    footer: decision.appealUrl
      ? `Not satisfied with this recommendation? Appeal here: ${decision.appealUrl}`
      : undefined,
  };
}
